+// resolveAgentTypeFilter determines the agent type filter from flags
+func resolveAgentTypeFilter() string {
+	// Explicit --agent flag takes precedence
+	if assignAgentType != "" {
+		return strings.ToLower(assignAgentType)
+	}
+	// Convenience flags
+	if assignCCOnly {
+		return "claude"
+	}
+	if assignCodOnly {
+		return "codex"
+	}
+	if assignGmiOnly {
+		return "gemini"
+	}
+	return "" // No filter
+}
