+	tests := []struct {
+		delay time.Duration
+		want  string
+	}{
+		{500 * time.Millisecond, "500ms"},
+		{1 * time.Second, "1.0s"},
+		{5500 * time.Millisecond, "5.5s"},
+		{90 * time.Second, "1.5m"},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.want, func(t *testing.T) {
+			got := FormatDelay(tt.delay)
+			if got != tt.want {
+				t.Errorf("FormatDelay(%v) = %q, want %q", tt.delay, got, tt.want)
+			}
+		})
+	}
